42	  Text() : str(L"") {}
43	  Text(std::wstring const& _str) : str(_str) {}
44	  void clear() {
45	    str.clear();
46	    attributes.clear();
47	  }
48	  bool empty() const { return str.empty(); }
49	  bool operator==(const Text& txt) {
50	    if (str != txt.str || (attributes.size() != txt.attributes.size()))
51	      return false;
52	    for (size_t i = 0; i < attributes.size(); i++) {
53	      if ((attributes[i] != txt.attributes[i]))
54	        return false;
55	    }
56	    return true;
57	  }
58	  bool operator!=(const Text& txt) {
59	    if (str != txt.str || (attributes.size() != txt.attributes.size()))
60	      return true;
61	    for (size_t i = 0; i < attributes.size(); i++) {
62	      if ((attributes[i] != txt.attributes[i]))
63	        return true;
