83	    candies.clear();
84	    labels.clear();
85	  }
86	  bool empty() const { return candies.empty(); }
87	  bool operator==(const CandidateInfo& ci) {
88	    if (currentPage != ci.currentPage || totalPages != ci.totalPages ||
89	        highlighted != ci.highlighted || is_last_page != ci.is_last_page ||
90	        notequal(candies, ci.candies) || notequal(comments, ci.comments) ||
91	        notequal(labels, ci.labels))
92	      return false;
93	    return true;
94	  }
95	  bool operator!=(const CandidateInfo& ci) {
96	    if (currentPage != ci.currentPage || totalPages != ci.totalPages ||
97	        highlighted != ci.highlighted || is_last_page != ci.is_last_page ||
98	        notequal(candies, ci.candies) || notequal(comments, ci.comments) ||
99	        notequal(labels, ci.labels))
100	      return true;
101	    return false;
