361	#define MAP_PIPE_MSG_HANDLE(__msg, __wParam, __lParam) \
362	  {                                                    \
363	    auto lParam = __lParam;                            \
364	    auto wParam = __wParam;                            \
365	    LRESULT _result = 0;                               \
366	    switch (__msg) {
367	#define PIPE_MSG_HANDLE(__msg, __func)       \
368	  case __msg:                                \
369	    _result = __func(__msg, wParam, lParam); \
370	    break;
371	
372	#define END_MAP_PIPE_MSG_HANDLE(__result) \
373	  }                                       \
374	  __result = _result;                     \
375	  }
