411	    try {
412	      boost::this_thread::interruption_point();
413	      pipe = _ConnectServerPipe(pname);
414	      boost::thread th(
415	          [&handler, pipe, this] { _ProcessPipeThread(pipe, handler); });
416	    } catch (DWORD ex) {
417	      _FinalizePipe(pipe);
418	    }
419	    boost::this_thread::interruption_point();
420	  }
