428	void PipeServer::_ProcessPipeThread(HANDLE pipe, ServerHandler const& handler) {
429	  try {
430	    for (;;) {
431	      Res msg;
432	      _Receive(pipe, &msg, sizeof(msg));
433	      handler(msg, [this, pipe](Msg resp) { _Send(pipe, resp); });
434	    }
435	  } catch (...) {
436	    _FinalizePipe(pipe);
437	  }
438	}
